SELECT a.*, p.name as project_name, e.name as creator_name, jc.name as job_category_name, r.role_name as role_name, c.name as category_name FROM tb_account a LEFT JOIN tb_project p ON a.project_id = p.id LEFT JOIN tb_employee e ON a.creator_id = e.id LEFT JOIN tb_job_category jc ON a.job_category_id = jc.id LEFT JOIN tb_role r ON a.role_id = r.id LEFT JOIN tb_employee creator ON a.creator_id = creator.id LEFT JOIN tb_role creator_role ON creator.role_id = creator_role.id LEFT JOIN tb_category c ON a.category_id = c.id WHERE 1=1
AND (a.creator_id = #{currentUserId} OR LOWER(creator_role.role_code) != 'boss')
AND a.creator_id = #{currentUserId}
AND a.project_id = #{projectId}
AND a.status = #{status}
ORDER BY a.create_time DESC

SELECT a.*, p.name as project_name, e.name as creator_name, jc.name as job_category_name, r.role_name as role_name, c.name as category_name FROM tb_account a LEFT JOIN tb_project p ON a.project_id = p.id LEFT JOIN tb_employee e ON a.creator_id = e.id LEFT JOIN tb_job_category jc ON a.job_category_id = jc.id LEFT JOIN tb_role r ON a.role_id = r.id LEFT JOIN tb_employee creator ON a.creator_id = creator.id LEFT JOIN tb_role creator_role ON creator.role_id = creator_role.id LEFT JOIN tb_category c ON a.category_id = c.id WHERE 1=1
AND (a.creator_id = #{currentUserId} OR LOWER(creator_role.role_code) != 'boss')
AND a.creator_id = #{currentUserId}
AND a.project_id = #{projectId}
AND a.status = #{status}
AND a.type = #{type}
AND e.name LIKE CONCAT('%', #{creatorName}, '%')
ORDER BY a.create_time DESC LIMIT #{pageSize} OFFSET #{offset}

SELECT COUNT(*)
FROM tb_account a
LEFT JOIN tb_employee creator ON a.creator_id = creator.id
LEFT JOIN tb_employee e ON a.creator_id = e.id
LEFT JOIN tb_role creator_role ON creator.role_id = creator_role.id
WHERE 1=1



    AND (a.creator_id = #{currentUserId} OR LOWER(creator_role.role_code) != 'boss')



    AND a.creator_id = #{currentUserId}


    AND a.project_id = #{projectId}


    AND a.status = #{status}


    AND a.type = #{type}


    AND e.name LIKE CONCAT('%', #{creatorName}, '%')

SELECT p.id as projectId, p.name as projectName, COALESCE(SUM(CASE WHEN a.type = 1 AND a.status = 5 THEN a.amount ELSE 0 END), 0) as income, COALESCE(SUM(CASE WHEN a.type = 2 AND a.status = 5 THEN a.amount ELSE 0 END), 0) as expense, COALESCE(SUM(CASE WHEN a.type = 1 AND a.status = 5 THEN a.amount ELSE 0 END), 0) - COALESCE(SUM(CASE WHEN a.type = 2 AND a.status = 5 THEN a.amount ELSE 0 END), 0) as balance FROM tb_project p LEFT JOIN tb_account a ON p.id = a.project_id AND a.status = 5
INNER JOIN tb_employee_project ep ON p.id = ep.project_id AND ep.employee_id = #{userId}
WHERE 1=1
AND DATE(a.create_time) >= #{startDate}
AND DATE(a.create_time) <= #{endDate}
GROUP BY p.id, p.name ORDER BY expense DESC

SELECT p.id as projectId, p.name as projectName, COALESCE(SUM(CASE WHEN a.type = 1 AND a.status = 5 THEN a.amount ELSE 0 END), 0) as income, COALESCE(SUM(CASE WHEN a.type = 2 AND a.status = 5 THEN a.amount ELSE 0 END), 0) as expense, COALESCE(SUM(CASE WHEN a.type = 1 AND a.status = 5 THEN a.amount ELSE 0 END), 0) - COALESCE(SUM(CASE WHEN a.type = 2 AND a.status = 5 THEN a.amount ELSE 0 END), 0) as balance FROM tb_project p LEFT JOIN tb_account a ON p.id = a.project_id WHERE p.id = #{projectId} AND a.status = 5
AND DATE(a.create_time) >= #{startDate}
AND DATE(a.create_time) <= #{endDate}
GROUP BY p.id, p.name

SELECT COALESCE(SUM(a.amount), 0)
FROM tb_account a
WHERE a.type = 1 AND a.status = 5

    AND a.project_id IN (
        SELECT project_id FROM tb_employee_project WHERE employee_id = #{userId}
    )


    AND DATE(a.create_time) >= #{startDate}


    AND DATE(a.create_time) <= #{endDate}

SELECT COALESCE(SUM(a.amount), 0)
FROM tb_account a
WHERE a.type = 2 AND a.status = 5

    AND a.project_id IN (
        SELECT project_id FROM tb_employee_project WHERE employee_id = #{userId}
    )


    AND DATE(a.create_time) >= #{startDate}


    AND DATE(a.create_time) <= #{endDate}

SELECT p.id as projectId, p.name as projectName, COALESCE(SUM(a.amount), 0) as income, 0 as expense, 0 as balance FROM tb_project p LEFT JOIN tb_account a ON p.id = a.project_id AND a.type = 1 AND a.status = 5
INNER JOIN tb_employee_project ep ON p.id = ep.project_id AND ep.employee_id = #{userId}
WHERE 1=1
AND DATE(a.create_time) >= #{startDate}
AND DATE(a.create_time) <= #{endDate}
GROUP BY p.id, p.name HAVING income > 0 ORDER BY income DESC LIMIT 5

SELECT p.id as projectId, p.name as projectName, 0 as income, COALESCE(SUM(a.amount), 0) as expense, 0 as balance FROM tb_project p LEFT JOIN tb_account a ON p.id = a.project_id AND a.type = 2 AND a.status = 5
INNER JOIN tb_employee_project ep ON p.id = ep.project_id AND ep.employee_id = #{userId}
WHERE 1=1
AND DATE(a.create_time) >= #{startDate}
AND DATE(a.create_time) <= #{endDate}
GROUP BY p.id, p.name HAVING expense > 0 ORDER BY expense DESC LIMIT 5

SELECT c.id as projectId, c.name as projectName, COALESCE(SUM(a.amount), 0) as income, 0 as expense, 0 as balance FROM tb_category c LEFT JOIN tb_account a ON c.id = a.category_id AND a.type = 1 AND a.status = 5 WHERE 1=1
AND DATE(a.create_time) >= #{startDate}
AND DATE(a.create_time) <= #{endDate}
GROUP BY c.id, c.name HAVING income > 0 ORDER BY income DESC LIMIT 5

SELECT c.id as projectId, c.name as projectName, 0 as income, COALESCE(SUM(a.amount), 0) as expense, 0 as balance FROM tb_category c LEFT JOIN tb_account a ON c.id = a.category_id AND a.type = 2 AND a.status = 5 WHERE 1=1
AND DATE(a.create_time) >= #{startDate}
AND DATE(a.create_time) <= #{endDate}
GROUP BY c.id, c.name HAVING expense > 0 ORDER BY expense DESC LIMIT 5

SELECT c.id as categoryId, c.name as categoryName, COALESCE(SUM(a.amount), 0) as amount FROM tb_account a LEFT JOIN tb_category c ON a.category_id = c.id WHERE a.project_id = #{projectId} AND a.type = 1 AND a.status = 5
AND DATE(a.create_time) >= #{startDate}
AND DATE(a.create_time) <= #{endDate}
GROUP BY c.id, c.name HAVING amount > 0 ORDER BY amount DESC

SELECT c.id as categoryId, c.name as categoryName, COALESCE(SUM(a.amount), 0) as amount FROM tb_account a LEFT JOIN tb_category c ON a.category_id = c.id WHERE a.project_id = #{projectId} AND a.type = 2 AND a.status = 5
AND DATE(a.create_time) >= #{startDate}
AND DATE(a.create_time) <= #{endDate}
GROUP BY c.id, c.name HAVING amount > 0 ORDER BY amount DESC

